import org.apache.poi.ss.usermodel.*
import org.apache.poi.xssf.usermodel.*
import java.io.File

/**
 * Generic Excel Reader using Apache POI 4.1.2
 * Compatible with newer POI versions
 */
def readExcelData(String filePath, int sheetIndex = 0, int startRow = 1) {
    FileInputStream fis = null
    XSSFWorkbook workbook = null

    try {
        log.info("=== READING EXCEL FILE ===")
        log.info("File Path: ${filePath}")

        def file = new File(filePath)
        if (!file.exists()) {
            log.error("Excel file not found: ${filePath}")
            return []
        }

        fis = new FileInputStream(file)
        workbook = new XSSFWorkbook(fis)

        def sheet = workbook.getSheetAt(sheetIndex)
        if (!sheet) {
            log.error("Sheet at index ${sheetIndex} not found")
            return []
        }

        // Read header row
        def headerRow = sheet.getRow(0)
        if (!headerRow) {
            log.error("No header row found")
            return []
        }

        def headers = []
        (0..headerRow.lastCellNum - 1).each { cellIdx ->
            def cell = headerRow.getCell(cellIdx)
            headers.add(cell?.stringCellValue ?: "Column_${cellIdx}")
        }

        log.info("Headers: ${headers}")

        def dataList = []

        // Read data rows
        (startRow..sheet.lastRowNum).each { rowIdx ->
            def row = sheet.getRow(rowIdx)
            if (row) {
                def rowMap = [:]

                (0..headers.size() - 1).each { cellIdx ->
                    def cell = row.getCell(cellIdx)
                    def value = ""

                    if (cell != null) {
                        // Use getCellType() method instead of cellType property
                        def cellType = cell.getCellType()

                        if (cellType == CellType.STRING) {
                            value = cell.getStringCellValue()
                        } else if (cellType == CellType.NUMERIC) {
                            if (DateUtil.isCellDateFormatted(cell)) {
                                value = cell.getDateCellValue()
                            } else {
                                value = cell.getNumericCellValue() as Integer
                            }
                        } else if (cellType == CellType.BOOLEAN) {
                            value = cell.getBooleanCellValue()
                        } else if (cellType == CellType.BLANK) {
                            value = ""
                        } else {
                            value = cell.toString()
                        }
                    }
                    rowMap[headers[cellIdx]] = value
                }

                if (rowMap) {
                    dataList.add(rowMap)
                    log.info("Row ${rowIdx}: ${rowMap}")
                }
            }
        }

        log.info("✓ Successfully read ${dataList.size()} rows from Excel")
        log.info("=== END READING EXCEL ===")

        return dataList

    } catch (Exception e) {
        log.error("ERROR reading Excel: ${e.message}")
        e.printStackTrace()
        return []

    } finally {
        // Close resources
        try {
            if (workbook) workbook.close()
            if (fis) fis.close()
        } catch (Exception e) {
            log.warn("Error closing resources: ${e.message}")
        }
    }
}

// ===== MAIN EXECUTION =====
def excelPath = "C:/TestData/subregions.xlsx"

log.info("\n*** Starting Excel Data Load ***")
def excelData = readExcelData(excelPath, 0, 1)

if (excelData.isEmpty()) {
    log.error("FAILED: No data read from Excel file!")
    testRunner.fail("Failed to read Excel data")
} else {
    // FIX: Use testRunner.testCase instead of testCase
    testRunner.testCase.setPropertyValue("excelData", excelData.toString())
    context.excelDataList = excelData

    log.info("\n*** Excel Data Loaded Successfully ***")
    log.info("Total rows: ${excelData.size()}")
    excelData.each { row ->
        log.info("  → ${row}")
    }
}

return excelData

import groovy.json.JsonSlurper

/**
 * Generic function to make GET API calls
 * Handles connection, response parsing, and error handling
 */
def makeGETRequest(String apiUrl) {
    try {
        log.info("Making GET request to: ${apiUrl}")

        // Create connection
        def url = new URL(apiUrl)
        def connection = url.openConnection() as HttpURLConnection
        connection.requestMethod = 'GET'
        connection.setRequestProperty('Accept', 'application/json')
        connection.setRequestProperty('Content-Type', 'application/json')
        connection.setConnectTimeout(10000)
        connection.setReadTimeout(10000)

        // Get response
        def responseCode = connection.responseCode
        log.info("Response Code: ${responseCode}")

        def responseBody = ""
        if (responseCode == 200) {
            responseBody = connection.inputStream.text
        } else {
            responseBody = connection.errorStream?.text ?: "No error details"
        }

        log.info("Response received (${responseBody.length()} bytes)")

        return [
            status: responseCode,
            data: responseBody,
            success: (responseCode == 200),
            timestamp: new Date().format('yyyy-MM-dd HH:mm:ss')
        ]

    } catch (Exception e) {
        log.error("ERROR making GET request: ${e.message}")
        e.printStackTrace()
        return [
            status: 500,
            data: null,
            success: false,
            error: e.message,
            timestamp: new Date().format('yyyy-MM-dd HH:mm:ss')
        ]
    }
}

// ===== MAIN EXECUTION =====
log.info("\n=== STARTING API REQUEST LOOP ===")

def excelData = context.excelDataList

if (!excelData || excelData.isEmpty()) {
    log.error("No test data available from Excel!")
    testRunner.fail("No test data to process")
    return
}

def apiBaseUrl = "https://restcountries.com/v3.1/subregion"
def apiResults = []

excelData.eachWithIndex { rowData, index ->
    try {
        def subregion = rowData['SubregionName']
        log.info("\n>>> Processing row ${index + 1}: Subregion = ${subregion}")

        // Replace spaces with %20 (proper URL encoding for spaces)
        def encodedSubregion = subregion.toString().replace(' ', '%20')
        def apiUrl = "${apiBaseUrl}/${encodedSubregion}"

        log.info("API URL: ${apiUrl}")

        // Make the API call directly
        def response = makeGETRequest(apiUrl)

        // Store result
        apiResults.add([
            rowNumber: index + 1,
            subregion: subregion,
            apiUrl: apiUrl,
            status: response.status,
            success: response.success,
            timestamp: response.timestamp,
            responseData: response.data,
            errorMessage: response.error ?: "None"
        ])

        log.info("✓ Result: Status ${response.status}, Success: ${response.success}")

        if (response.success) {
            // Store the response for validation in next step
            context.lastApiResponse = response.data
            testRunner.testCase.setPropertyValue("lastResponse", response.data)
        }

    } catch (Exception e) {
        log.error("ERROR processing row ${index}: ${e.message}")
        e.printStackTrace()
    }
}

// Store all results in context
context.apiResults = apiResults
testRunner.testCase.setPropertyValue("apiResults", apiResults.toString())

log.info("\n=== API REQUEST LOOP COMPLETED ===")
log.info("Total requests: ${apiResults.size()}")
log.info("Successful: ${apiResults.count { it.success }}")
log.info("Failed: ${apiResults.count { !it.success }}")

return apiResults

import groovy.json.JsonSlurper

/**
 * Comprehensive assertion script to validate API responses
 * Checks status, JSON validity, data integrity, and performance
 */

log.info("\n=== STARTING RESPONSE VALIDATION ===")

try {
    def apiResults = context.apiResults

    if (!apiResults || apiResults.isEmpty()) {
        log.error("No API results to validate!")
        testRunner.fail("No API results available")
        return
    }

    log.info("Total API calls made: ${apiResults.size()}")

    // ===== ASSERTION 1: Check HTTP Status Codes =====
    log.info("\n[ASSERTION 1] Validating HTTP Status Codes...")
    def failedRequests = apiResults.findAll { !it.success }

    if (failedRequests) {
        log.warn("WARNING: ${failedRequests.size()} requests failed:")
        failedRequests.each { result ->
            log.warn("  - ${result.subregion}: Status ${result.status}")
        }
    } else {
        log.info("✓ PASS: All requests returned status 200")
    }

    // ===== ASSERTION 2: Validate Response Data =====
    log.info("\n[ASSERTION 2] Validating Response Data...")
    def successfulResults = apiResults.findAll { it.success }

    if (successfulResults.isEmpty()) {
        log.error("ERROR: No successful responses to validate")
        testRunner.fail("All API calls failed")
        return
    }

    log.info("Validating ${successfulResults.size()} successful responses...")

    successfulResults.each { result ->
        def responseBody = result.responseData

        if (!responseBody) {
            log.error("No response body for ${result.subregion}")
            return
        }

        try {
            def jsonResponse = new JsonSlurper().parseText(responseBody)

            // Validate it's a list
            assert jsonResponse instanceof List, "Response should be a list"
            log.info("  ✓ ${result.subregion}: Valid JSON, ${jsonResponse.size()} countries")

            // Validate required fields
            def requiredFields = ['name', 'region', 'subregion']
            jsonResponse.each { country ->
                requiredFields.each { field ->
                    assert country.containsKey(field), "Missing field: ${field}"
                }
            }

            log.info("  ✓ ${result.subregion}: All required fields present")

        } catch (Exception e) {
            log.error("  ✗ ${result.subregion}: Validation failed - ${e.message}")
        }
    }

    // ===== ASSERTION 3: Summary Report =====
    log.info("\n" + "="*60)
    log.info("*** VALIDATION SUMMARY ***")
    log.info("Total API Calls: ${apiResults.size()}")
    log.info("Successful: ${successfulResults.size()}")
    log.info("Failed: ${failedRequests.size()}")

    successfulResults.each { result ->
        log.info("  ✓ ${result.subregion} (${result.apiUrl})")
    }

    failedRequests.each { result ->
        log.info("  ✗ ${result.subregion} (Status: ${result.status})")
    }

    log.info("="*60)

    if (successfulResults.size() > 0) {
        log.info("\n*** VALIDATION PASSED ***")
    }

} catch (Exception e) {
    log.error("ERROR in validation: ${e.message}")
    e.printStackTrace()
    testRunner.fail("Validation failed: ${e.message}")
}

return true
